Code Good:
interface ProductApi {
    @GET('api/products')
    suspend fun getProducts(): ApiResponse<List<ProductDto>>

    @GET('api/products/{id}')
    suspend fun getProduct(@Path('id') id: String): ApiResponse<ProductDto>

    @POST('api/orders')
    suspend fun createOrder(@Body order: CreateOrderRequest): ApiResponse<OrderDto>
}

// With error handling in repository
class ProductRepositoryImpl @Inject constructor(
    private val api: ProductApi
) : ProductRepository {
    override suspend fun getProducts(): Result<List<Product>> = runCatching {
        api.getProducts().data.map { it.toDomain() }
    }
}

