@Test
fun `loadProducts emits success state`() = runTest {
    val mockRepo = mockk<ProductRepository>()
    coEvery { mockRepo.getProducts() } returns Result.success(listOf(testProduct))

    val viewModel = ProductViewModel(mockRepo)

    viewModel.state.test {
        assertEquals(UiState.Loading, awaitItem())
        assertEquals(UiState.Success(listOf(testProduct)), awaitItem())
    }
}

